import icon from "../assets/icon.png";

const Header = () => {
    return (
        <header>
            <section className="flex items-center m-4">
                <img src={icon} className="scale-75"/>
                <h1 style={{ fontFamily: 'Viga-Regular' }} className="uppercase text-5xl text-sky-700 p">Film Focusd</h1>
            </section>
        </header>
    )
}

export default Header;
